import { webContents } from 'electron';
import { randomUUID } from 'crypto';
import type { Client, ClientChannel } from 'ssh2';
import { IPC_CHANNELS } from '../ipc/types';
import { sshService } from './SSHService';

interface TerminalSession {
  sessionId: string;
  serverId: string;
  stream: ClientChannel;
  webContentsId: number;
  closed: boolean;
  listeners: {
    onData: (data: Buffer | string) => void;
    onStderr: (data: Buffer | string) => void;
    onClose: () => void;
    onExit: (code: number | null, signal: string | null) => void;
    onError: (error: Error) => void;
  };
}

interface CreateSessionOptions {
  serverId: string;
  cols: number;
  rows: number;
  webContentsId: number;
}

class TerminalService {
  private sessions: Map<string, TerminalSession> = new Map();

  async createSession(options: CreateSessionOptions): Promise<{ sessionId: string }> {
    const client = await this.ensureConnection(options.serverId);
    const sessionId = randomUUID();

    const stream = await new Promise<ClientChannel>((resolve, reject) => {
      client.shell(
        {
          term: 'xterm-256color',
          cols: options.cols,
          rows: options.rows,
        },
        (error, channel) => {
          if (error || !channel) {
            reject(error ?? new Error('Failed to establish interactive shell.'));
            return;
          }
          resolve(channel);
        },
      );
    });

    const onData = (chunk: Buffer | string) => {
      this.emitData(options.webContentsId, sessionId, chunk);
    };

    const onStderr = (chunk: Buffer | string) => {
      this.emitData(options.webContentsId, sessionId, chunk);
    };

    const onClose = () => {
      this.handleExit(sessionId, null, null);
    };

    const onExit = (code: number | null, signal: string | null) => {
      this.handleExit(sessionId, code, signal);
    };

    const onError = (error: Error) => {
      this.emitData(options.webContentsId, sessionId, `\r\n${error.message}\r\n`);
      this.handleExit(sessionId, null, null);
    };

    stream.on('data', onData);
    // For shell channels stderr is multiplexed; stream.stderr may still emit
    if (stream.stderr) {
      stream.stderr.on('data', onStderr);
    }
    stream.on('close', onClose);
    stream.on('exit', onExit);
    stream.on('error', onError);

    this.sessions.set(sessionId, {
      sessionId,
      serverId: options.serverId,
      stream,
      webContentsId: options.webContentsId,
      closed: false,
      listeners: { onData, onStderr, onClose, onExit, onError },
    });

    return { sessionId };
  }

  async write(sessionId: string, data: string): Promise<void> {
    const session = this.sessions.get(sessionId);
    if (!session || session.closed) {
      throw new Error('Terminal session not found.');
    }
    session.stream.write(data);
  }

  async resize(sessionId: string, cols: number, rows: number): Promise<void> {
    const session = this.sessions.get(sessionId);
    if (!session || session.closed) {
      return;
    }
    try {
      // The SSH spec expects rows first, then cols. Height/width in pixels are optional.
      session.stream.setWindow(rows, cols, 0, 0);
    } catch (error) {
      // Ignore resize errors; remote shells may not support window resizing.
    }
  }

  async close(sessionId: string): Promise<void> {
    const session = this.sessions.get(sessionId);
    if (!session) {
      return;
    }
    try {
      session.stream.end();
    } catch {
      // ignore
    }
    this.handleExit(sessionId, null, null);
  }

  private async ensureConnection(serverId: string): Promise<Client> {
    return sshService.connect(serverId);
  }

  private emitData(targetId: number, sessionId: string, chunk: Buffer | string) {
    const contents = webContents.fromId(targetId);
    if (!contents || contents.isDestroyed()) {
      return;
    }
    const payload = Buffer.isBuffer(chunk) ? chunk.toString('utf8') : chunk;
    if (!payload) {
      return;
    }
    contents.send(IPC_CHANNELS.TERMINAL_DATA, {
      sessionId,
      data: payload,
    });
  }

  private handleExit(sessionId: string, code: number | null, signal: string | null) {
    const session = this.sessions.get(sessionId);
    if (!session || session.closed) {
      return;
    }

    const contents = webContents.fromId(session.webContentsId);
    this.cleanup(sessionId);

    if (contents && !contents.isDestroyed()) {
      contents.send(IPC_CHANNELS.TERMINAL_EXIT, { sessionId, code, signal });
    }
  }

  private cleanup(sessionId: string) {
    const session = this.sessions.get(sessionId);
    if (!session) {
      return;
    }

    session.closed = true;
    this.sessions.delete(sessionId);

    const { stream, listeners } = session;
    stream.off('data', listeners.onData);
    if (stream.stderr) {
      stream.stderr.off('data', listeners.onStderr);
    }
    stream.off('close', listeners.onClose);
    stream.off('exit', listeners.onExit);
    stream.off('error', listeners.onError);
  }
}

export const terminalService = new TerminalService();
